class Solution:
    def findNumOfValidWords(self, words, puzzles):
        wsets = [set(w) for w in words]
        res = []
        for p in puzzles:
            first = p[0]
            ps = set(p)
            cnt = 0
            for ws in wsets:
                if first in ws and ws <= ps:
                    cnt += 1
            res.append(cnt)
        return res

