class Solution:
    def findNumOfValidWords(self, words, puzzles):
        from collections import Counter
        def mask(w):
            m = 0
            for c in w:
                m |= 1 << (ord(c) - 97)
            return m
        wc = Counter(mask(w) for w in words)
        res = []
        for p in puzzles:
            pm = mask(p)
            first = 1 << (ord(p[0]) - 97)
            total = 0
            sub = pm
            while sub:
                if sub & first:
                    total += wc.get(sub, 0)
                sub = (sub - 1) & pm
            res.append(total)
        return res

