var findNumOfValidWords = function(words, puzzles) {
    const mask = w => {
        let m = 0;
        for (const c of w) m |= 1 << (c.charCodeAt(0) - 97);
        return m;
    };
    const wc = new Map();
    for (const w of words) {
        const m = mask(w);
        wc.set(m, (wc.get(m) || 0) + 1);
    }
    return puzzles.map(p => {
        const pm = mask(p);
        const first = 1 << (p.charCodeAt(0) - 97);
        let total = 0;
        let sub = pm;
        while (sub) {
            if (sub & first) total += wc.get(sub) || 0;
            sub = (sub - 1) & pm;
        }
        return total;
    });
};
